import React, { useState, useEffect } from 'react';

// --- MOCK DATA FÜR DIE DEMO (Simuliert die Datenbank-Verknüpfungen) ---
const initialUsers = [
    { id: 1, username: 'admin', role: 'ADMIN', name: 'Alice (Admin)' },
    { id: 2, username: 'manager', role: 'MANAGER', name: 'Bob (Projektleiter)' },
    { id: 3, username: 'employee1', role: 'EMPLOYEE', name: 'Charlie (Mitarbeiter)' },
    { id: 4, username: 'employee2', role: 'EMPLOYEE', name: 'Diana (Mitarbeiterin)' },
];

const initialTasks = [
    { id: 101, projectId: 1, title: 'Server aufsetzen', status: 'DONE' },
{ id: 102, projectId: 1, title: 'Datenbank migrieren', status: 'IN_PROGRESS' },
{ id: 103, projectId: 1, title: 'SSL Zertifikate prüfen', status: 'OPEN' },
];

function App() {
    // --- STATES ---
    const [currentUser, setCurrentUser] = useState(null); // Login-Status
    const [view, setView] = useState('dashboard'); // 'dashboard', 'projectDetail', 'admin'
    const [projects, setProjects] = useState([]);
    const [tasks, setTasks] = useState(initialTasks);
    const [users, setUsers] = useState(initialUsers);
    const [selectedProject, setSelectedProject] = useState(null);

    // Formular-States
    const [newProject, setNewProject] = useState({ name: '', description: '' });
    const [newTask, setNewTask] = useState('');
    const [newUser, setNewUser] = useState({ username: '', role: 'EMPLOYEE', name: '' });

    // --- BACKEND-ANBINDUNG (Projekte) ---
    useEffect(() => {
        if (currentUser) {
            fetch('http://localhost:8081/api/projects')
            .then(res => res.ok ? res.json() : [])
            .then(data => {
                // Wir reichern die Backend-Daten für die Demo mit fiktiven Zuweisungen an
                const enhancedProjects = data.map(p => ({
                    ...p,
                    status: p.status || 'ACTIVE',
                    assignedUsers: [3, 4] // Charlie & Diana sind zugewiesen
                }));
                setProjects(enhancedProjects);
            })
            .catch(() => setProjects([{ id: 1, name: 'Fallback Projekt', description: 'Backend offline', status: 'ACTIVE', assignedUsers: [3] }]));
        }
    }, [currentUser]);

    // --- LOGIK & BERECHNUNGEN ---
    const handleLogin = (userId) => {
        setCurrentUser(users.find(u => u.id === userId));
        setView('dashboard');
    };

    const calculateProgress = (projectId) => {
        const projectTasks = tasks.filter(t => t.projectId === projectId);
        if (projectTasks.length === 0) return 0;
        const doneTasks = projectTasks.filter(t => t.status === 'DONE').length;
        // Mathematische Berechnung des Fortschritts
        return Math.round((doneTasks / projectTasks.length) * 100);
    };

    // Sichtbarkeits-Filter (Wer darf was sehen?)
    const visibleProjects = projects.filter(p => {
        if (currentUser.role === 'ADMIN') return true;
        if (currentUser.role === 'MANAGER') return p.status !== 'ARCHIVED'; // Manager sehen aktive
        // Mitarbeiter sehen nur ihre zugewiesenen & aktiven
        return p.status !== 'ARCHIVED' && p.assignedUsers?.includes(currentUser.id);
    });

    // --- AKTIONEN ---
    const createProject = (e) => {
        e.preventDefault();
        const created = { id: Date.now(), name: newProject.name, description: newProject.description, status: 'ACTIVE', assignedUsers: [] };
        setProjects([...projects, created]);
        setNewProject({ name: '', description: '' });
    };

    const archiveProject = (id) => {
        setProjects(projects.map(p => p.id === id ? { ...p, status: 'ARCHIVED' } : p));
    };

    const createTask = (e) => {
        e.preventDefault();
        setTasks([...tasks, { id: Date.now(), projectId: selectedProject.id, title: newTask, status: 'OPEN' }]);
        setNewTask('');
    };

    const updateTaskStatus = (taskId, newStatus) => {
        setTasks(tasks.map(t => t.id === taskId ? { ...t, status: newStatus } : t));
    };

    const createUser = (e) => {
        e.preventDefault();
        setUsers([...users, { id: Date.now(), ...newUser }]);
        setNewUser({ username: '', role: 'EMPLOYEE', name: '' });
    };

    // --- VIEWS ---
    // 1. LOGIN SCREEN
    if (!currentUser) {
        return (
            <div style={styles.loginScreen}>
            <div style={styles.loginCard}>
            <div style={styles.logo}>✦ Nexus<span style={{fontWeight: 300}}>Task</span></div>
            <p style={{color: '#718096', marginBottom: '30px'}}>Bitte wähle eine Rolle, um das System zu testen:</p>
            {users.map(u => (
                <button key={u.id} onClick={() => handleLogin(u.id)} style={styles.loginBtn}>
                Als {u.name} anmelden
                </button>
            ))}
            </div>
            </div>
        );
    }

    // 2. ADMIN PANEL
    if (view === 'admin') {
        return (
            <DashboardLayout user={currentUser} setView={setView} logout={() => setCurrentUser(null)}>
            <h2 style={styles.pageTitle}>Benutzerverwaltung</h2>
            <div style={styles.glassCard}>
            <h3 style={styles.cardTitle}>Neuen Benutzer anlegen</h3>
            <form onSubmit={createUser} style={styles.formRow}>
            <input style={styles.input} placeholder="Voller Name" value={newUser.name} onChange={e => setNewUser({...newUser, name: e.target.value})} required/>
            <input style={styles.input} placeholder="Benutzername" value={newUser.username} onChange={e => setNewUser({...newUser, username: e.target.value})} required/>
            <select style={styles.select} value={newUser.role} onChange={e => setNewUser({...newUser, role: e.target.value})}>
            <option value="EMPLOYEE">Mitarbeiter</option>
            <option value="MANAGER">Projektleiter</option>
            <option value="ADMIN">Administrator</option>
            </select>
            <button style={styles.btnPrimary}>Anlegen</button>
            </form>
            </div>
            <div style={styles.userGrid}>
            {users.map(u => (
                <div key={u.id} style={styles.userCard}>
                <div style={styles.avatar}>{u.name.charAt(0)}</div>
                <div>
                <div style={{fontWeight: 'bold', color: '#2d3748'}}>{u.name}</div>
                <div style={{fontSize: '12px', color: '#a0aec0'}}>{u.role}</div>
                </div>
                </div>
            ))}
            </div>
            </DashboardLayout>
        );
    }

    // 3. PROJECT DETAILS & TASKS (Kanban-Style)
    if (selectedProject) {
        const projectTasks = tasks.filter(t => t.projectId === selectedProject.id);
        const progress = calculateProgress(selectedProject.id);

        return (
            <DashboardLayout user={currentUser} setView={setView} logout={() => setCurrentUser(null)}>
            <button onClick={() => setSelectedProject(null)} style={styles.btnBack}>← Zurück zur Übersicht</button>

            <div style={styles.projectHeader}>
            <div>
            <h2 style={styles.pageTitle}>{selectedProject.name}</h2>
            <p style={{color: '#718096'}}>{selectedProject.description}</p>
            </div>
            <div style={styles.progressContainer}>
            <div style={{display: 'flex', justifyContent: 'space-between', marginBottom: '5px'}}>
            <span style={{fontSize: '14px', fontWeight: 'bold', color: '#4a5568'}}>Projektfortschritt</span>
            <span style={{fontSize: '14px', color: '#48bb78'}}>{progress}%</span>
            </div>
            <div style={styles.progressBarBg}>
            <div style={{...styles.progressBarFill, width: `${progress}%`}}></div>
            </div>
            </div>
            </div>

            {/* Task Formular */}
            {(currentUser.role === 'EMPLOYEE' || currentUser.role === 'MANAGER') && selectedProject.status !== 'ARCHIVED' && (
                <form onSubmit={createTask} style={{...styles.formRow, marginBottom: '30px'}}>
                <input style={styles.input} placeholder="Neue Aufgabe eingeben..." value={newTask} onChange={e => setNewTask(e.target.value)} required/>
                <button style={styles.btnPrimary}>Task hinzufügen</button>
                </form>
            )}

            {/* Kanban Board */}
            <div style={styles.kanbanBoard}>
            {['OPEN', 'IN_PROGRESS', 'DONE'].map(status => (
                <div key={status} style={styles.kanbanColumn}>
                <h4 style={styles.kanbanTitle}>{status === 'OPEN' ? 'To Do 📝' : status === 'IN_PROGRESS' ? 'In Arbeit ⚙️' : 'Erledigt ✅'}</h4>
                {projectTasks.filter(t => t.status === status).map(t => (
                    <div key={t.id} style={styles.taskCard}>
                    <div style={{marginBottom: '15px'}}>{t.title}</div>
                    <select
                    style={styles.taskSelect}
                    value={t.status}
                    onChange={e => updateTaskStatus(t.id, e.target.value)}
                    disabled={selectedProject.status === 'ARCHIVED'}
                    >
                    <option value="OPEN">Offen</option>
                    <option value="IN_PROGRESS">In Bearbeitung</option>
                    <option value="DONE">Erledigt</option>
                    </select>
                    </div>
                ))}
                </div>
            ))}
            </div>
            </DashboardLayout>
        );
    }

    // 4. MAIN DASHBOARD
    return (
        <DashboardLayout user={currentUser} setView={setView} logout={() => setCurrentUser(null)}>
        <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px'}}>
        <h2 style={styles.pageTitle}>Dashboard</h2>
        </div>

        {currentUser.role === 'MANAGER' && (
            <div style={styles.glassCard}>
            <h3 style={styles.cardTitle}>Neues Projekt initiieren</h3>
            <form onSubmit={createProject} style={styles.formRow}>
            <input style={styles.input} placeholder="Projektname" value={newProject.name} onChange={e => setNewProject({...newProject, name: e.target.value})} required/>
            <input style={styles.input} placeholder="Ziel / Beschreibung" value={newProject.description} onChange={e => setNewProject({...newProject, description: e.target.value})} required/>
            <button style={styles.btnPrimary}>Projekt starten</button>
            </form>
            </div>
        )}

        <div style={styles.projectGrid}>
        {visibleProjects.map(p => {
            const progress = calculateProgress(p.id);
            return (
                <div key={p.id} style={styles.projectCard}>
                <div style={styles.cardHeaderTop}>
                <span style={p.status === 'ARCHIVED' ? styles.badgeArchived : styles.badgeActive}>
                {p.status}
                </span>
                {currentUser.role === 'MANAGER' && p.status !== 'ARCHIVED' && (
                    <button onClick={() => archiveProject(p.id)} style={styles.btnDangerText}>Archivieren</button>
                )}
                </div>
                <h3 style={styles.projectTitle}>{p.name}</h3>
                <p style={styles.projectDesc}>{p.description}</p>

                <div style={{marginTop: 'auto'}}>
                <div style={styles.progressBarBgSmall}>
                <div style={{...styles.progressBarFillSmall, width: `${progress}%`}}></div>
                </div>
                <button onClick={() => setSelectedProject(p)} style={styles.btnSecondaryFull}>Projekt öffnen</button>
                </div>
                </div>
            )
        })}
        {visibleProjects.length === 0 && <p style={{color: '#a0aec0'}}>Keine Projekte zugewiesen oder verfügbar.</p>}
        </div>
        </DashboardLayout>
    );
}

// --- REUSABLE LAYOUT COMPONENT ---
const DashboardLayout = ({ user, setView, logout, children }) => (
    <div style={styles.appLayout}>
    <aside style={styles.sidebar}>
    <div style={styles.sidebarLogo}>✦ Nexus<span style={{fontWeight: 300}}>Task</span></div>
    <nav style={styles.nav}>
    <button onClick={() => setView('dashboard')} style={styles.navLink}>📊 Übersicht</button>
    {user.role === 'ADMIN' && <button onClick={() => setView('admin')} style={styles.navLink}>👥 Benutzerverwaltung</button>}
    </nav>
    <div style={styles.userInfo}>
